// 1. Получаем входные данные
const rawOutput = $input.first().json.output;
let allCases = [];

// 2. Блок парсинга
try {
  if (typeof rawOutput === 'object' && rawOutput !== null) {
    allCases = Array.isArray(rawOutput) ? rawOutput : [rawOutput];
  } else if (typeof rawOutput === 'string') {
    const parsed = JSON.parse(rawOutput);
    allCases = Array.isArray(parsed) ? parsed : [parsed];
  }
} catch (e) {
  // Попытка "хирургии"
  try {
    if (typeof rawOutput === 'string') {
      const lastBraceIndex = rawOutput.lastIndexOf('}');
      if (lastBraceIndex !== -1) {
        const fixedString = rawOutput.substring(0, lastBraceIndex + 1) + ']';
        const parsed = JSON.parse(fixedString);
        allCases = Array.isArray(parsed) ? parsed : [parsed];
      }
    }
  } catch (e2) {
    // Критическая ошибка - возвращаем диагностику
    return [{
      json: {
        error: 'Parsing failed',
        rawType: typeof rawOutput,
        rawSample: String(rawOutput).substring(0, 200)
      }
    }];
  }
}

// 3. Проверка что allCases - массив
if (!Array.isArray(allCases)) {
  return [{
    json: {
      error: 'Data is not an array',
      dataType: typeof allCases,
      data: allCases
    }
  }];
}

// 4. Вспомогательная функция
const getValue = (item, possibleKeys) => {
  for (let key of possibleKeys) {
    if (item.hasOwnProperty(key) && item[key] !== undefined && item[key] !== null) {
      return item[key];
    }
  }
  return "";
};

// 5. Маппинг данных
return allCases.map(item => ({
  json: {
    номер: getValue(item, ["№", "Номер", "number", "card_id", "id"]),
    аналитика: getValue(item, ["Аналитика", "analytics", "text", "description"]),
    оценка: getValue(item, ["Оценка", "score", "rating"]),
    группа: getValue(item, ["Группа", "group", "category"])
  }
}));

