  data = JSON.parse(rawOutput);
} catch (error) {
  throw new Error('Не удалось распарсить JSON: ' + error.message);
}

// Проверяем, что это массив
if (!Array.isArray(data)) {
  throw new Error('После парсинга должен быть массив, получено: ' + typeof data);
}

return data.map(item => ({
  json: {
    номер_карты: item['Карта_Id'] || '',
    исходный_кейс: item['Номер_кейса'] || '',
    название: item['Название'] || '',
    луч: item['Луч'] || '',
    описание: item['Description'] || '',
    задача: item['Task'] || '',
    допматериал: item['Доп_материал'] || '',
    типЗадачи: item['Доп. материал'] || ''
  }
}));

const allCases = $input.first().json.data;

const filtered = allCases.map(item => ({
  Номер: item['Номер'],
  Название_кейса: item['Название кейса'],
  Суть: item['Суть']
}));

return [{
  json: {
    кейсы: filtered
  }
}];

