// 1. Получаем данные и делаем двойной парсинг
let rawOutput = $input.first().json.output;

// Первый парсинг: если это JSON-строка массива
let parsedData;
try {
  parsedData = typeof rawOutput === 'string' ? JSON.parse(rawOutput) : rawOutput;
} catch (e) {
  parsedData = rawOutput;
}

// Берем первый элемент, если это массив
let inputText = Array.isArray(parsedData) ? parsedData[0] : parsedData;

// 2. Разбиваем по разделителю ───
const blocks = inputText.split(/\n───\n/).filter(b => b.trim());

// 3. Обрабатываем каждый блок
const results = blocks.map(block => {
  const lines = block.trim().split('\n\n'); // Используем двойной перенос

  // Первый элемент - заголовок
  const headerLine = lines[0] || "";
  const numberMatch = headerLine.match(/№(\d+)/);
  const number = numberMatch ? numberMatch[1] : "";

  // Второй элемент - промпт
  const prompt = lines[1] || "";

  // Убираем префикс типа из заголовка
  const title = headerLine
    .replace(/^(Текст|Аудио|Изображение|Видео|Интерактив|Данные)\s*№\d+\s*/, '')
    .trim();

  return {
    json: {
      title: title,
      number: number,
      prompt: prompt
    }
  };
});

return results;

// 1. Безопасно парсим входные данные
let rawOutput = $input.first().json.output;
let inputData;
try {
  // Если это строка JSON, парсим её. Если уже объект — оставляем.
  inputData = typeof rawOutput === 'string' ? JSON.parse(rawOutput) : rawOutput;
} catch (e) {
  inputData = []; 
}

// Вспомогательная функция для очистки промпта от оберток ```text или ```markdown
function cleanPrompt(text) {
  if (!text) return "";
  return text
    .replace(/^```(markdown|text|json)?\s*/i, '') // Убираем начало ```text
    .replace(/^```\s*/, '')                        // Убираем просто ```
    .replace(/\s*```$/, '')                        // Убираем конец ```
    .trim();
}

const results = inputData.map(item => {
  let title = "";
  let number = "";
  let prompt = "";

  // === ВАРИАНТ 1: Элемент массива — СТРОКА (Markdown) ===
  if (typeof item === 'string') {
    // Сценарий А: Заголовок СНАРУЖИ (Ваш последний пример: "Текст №1...\n\n```text...")
    // Ищем текст до ```, затем содержимое внутри ```
    const matchOutside = item.match(/^(.*?)\s*```(?:text|markdown)?\s*([\s\S]*?)\s*```/);

    // Сценарий Б: Заголовок ВНУТРИ (Ваш предыдущий пример: "```markdown\nТекст №1...\n\n...")
    // Ищем начало блока, потом заголовок, два переноса, потом промпт
    const matchInside = item.match(/^```(?:markdown|text)?\s*(.*?)\n\n([\s\S]*?)\s*```/);

    if (matchOutside && !item.trim().startsWith('```')) {
      // Сработал Сценарий А (заголовок перед кодом)
      title = matchOutside[1].trim();
      prompt = matchOutside[2].trim();
    } else if (matchInside) {
      // Сработал Сценарий Б (заголовок внутри кода)
      title = matchInside[1].trim();
      prompt = matchInside[2].trim();
    } else {
      // Если регулярки не сработали, просто чистим текст
      prompt = cleanPrompt(item);
    }
  } 

  // === ВАРИАНТ 2: Элемент массива — ОБЪЕКТ (JSON) ===
  else if (typeof item === 'object' && item !== null) {
    if ('card_id' in item || 'header' in item) {
      // Формат с card_id
      title = item.header || "";
      number = item.card_id || "";
      prompt = cleanPrompt(item.prompt_code);
    } else {
      // Формат с "Номер" и "Промт"
      title = ""; 
      number = item["Номер"] || "";
      prompt = cleanPrompt(item["Промт"]);
    }
  }

  // === ФИНАЛЬНАЯ ОБРАБОТКА ===
  // Если номер не найден в явном поле (card_id/Номер), вытаскиваем его из начала текста промпта
  if (!number && prompt) {
    const numMatch = prompt.match(/^(\d+)/);
    number = numMatch ? numMatch[1] : "";
  }

  return {
    json: {
      title: title,
      number: number,
      prompt: prompt
    }
  };
});

return results;

const html = $input.first().json.html || '';
const documentId = $input.first().json.id; // ✅ было .documentId — не работало

let plainText = html
  .replace(/<h2>(.*?)<\/h2>/g, '\n\n###H2###$1###H2END###\n')
  .replace(/<h3>(.*?)<\/h3>/g, '\n###H3###$1###H3END###\n')
  .replace(/<strong>(.*?)<\/strong>/g, '###BOLD###$1###BOLDEND###')
  .replace(/<p>/g, '')
  .replace(/<\/p>/g, '\n')
  .replace(/<ul>/g, '').replace(/<\/ul>/g, '')
  .replace(/<ol>/g, '').replace(/<\/ol>/g, '')
  .replace(/<li>/g, '• ').replace(/<\/li>/g, '\n')
  .replace(/<table>/g, '').replace(/<\/table>/g, '\n')
  .replace(/<tr>/g, '').replace(/<\/tr>/g, '\n')
  .replace(/<td>/g, '').replace(/<\/td>/g, ' | ')
  .replace(/<th>/g, '').replace(/<\/th>/g, ' | ')
  .replace(/<br\s*\/?>/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const requests = [];

const cleanText = plainText
  .replace(/###H2###/g, '').replace(/###H2END###/g, '')
  .replace(/###H3###/g, '').replace(/###H3END###/g, '')
  .replace(/###BOLD###/g, '').replace(/###BOLDEND###/g, '');

requests.push({
  insertText: { location: { index: 1 }, text: cleanText }
});

const h2Regex = /###H2###(.*?)###H2END###/g;
let match;
while ((match = h2Regex.exec(plainText)) !== null) {
  const headerText = match[1];
  const startIndex = cleanText.indexOf(headerText);
  if (startIndex >= 0) {
    requests.push({
      updateParagraphStyle: {
        range: { startIndex: startIndex + 1, endIndex: startIndex + 1 + headerText.length },
        paragraphStyle: { namedStyleType: 'HEADING_2' },
        fields: 'namedStyleType'
      }
    });
  }
}

const h3Regex = /###H3###(.*?)###H3END###/g;
while ((match = h3Regex.exec(plainText)) !== null) {
  const headerText = match[1];
  const startIndex = cleanText.indexOf(headerText);
  if (startIndex >= 0) {
    requests.push({
      updateParagraphStyle: {
        range: { startIndex: startIndex + 1, endIndex: startIndex + 1 + headerText.length },
        paragraphStyle: { namedStyleType: 'HEADING_3' },
        fields: 'namedStyleType'
      }
    });
  }
}

const boldRegex = /###BOLD###(.*?)###BOLDEND###/g;
let offset = 0;
const cleanTextForBold = plainText.replace(/###H2###|###H2END###|###H3###|###H3END###/g, '');
while ((match = boldRegex.exec(cleanTextForBold)) !== null) {
  const boldText = match[1];
  const startIndex = cleanText.indexOf(boldText, offset);
  if (startIndex >= 0) {
    requests.push({
      updateTextStyle: {
        range: { startIndex: startIndex + 1, endIndex: startIndex + 1 + boldText.length },
        textStyle: { bold: true },
        fields: 'bold'
      }
    });
    offset = startIndex + boldText.length;
  }
}

return {
  json: {
    documentId,
    requests // ✅ было JSON.stringify — не работало в n8n 4.3
  }
};

